const fmtBRL = v => v == null ? "—" : new Intl.NumberFormat("pt-BR",{style:"currency",currency:"BRL",maximumFractionDigits:0}).format(v);
const fmtBRL2 = v => v == null ? "—" : new Intl.NumberFormat("pt-BR",{style:"currency",currency:"BRL",maximumFractionDigits:2}).format(v);
const fmtN = v => v == null ? "—" : new Intl.NumberFormat("pt-BR").format(v);
const fmtK = v => v == null ? "—" : v>=1e6?`R$ ${(v/1e6).toFixed(1)}M`:v>=1e3?`R$ ${(v/1e3).toFixed(0)}K`:fmtBRL(v);

const REGIOES = ["Todas","Norte","Nordeste","Sudeste","Sul","Centro-Oeste"];
const PORTES = ["Todos","Pequeno I","Pequeno II","Médio","Grande","Metrópole"];
const SERVICOS = ["PAIF","SCFV","EV","LAS","Acessuas","Primeira Infância"];
const REGCOL = {Norte:"#22c55e",Nordeste:"#f59e0b",Sudeste:"#3b82f6",Sul:"#a855f7","Centro-Oeste":"#ef4444"};
const CKCOL = ["#00d4aa","#f59e0b","#6366f1","#ec4899","#22c55e","#f97316"];

const S = {
  app:{fontFamily:"'DM Sans','Segoe UI',sans-serif",background:"#070d1a",minHeight:"100vh",color:"#e2e8f0"},
  header:{background:"linear-gradient(135deg,#0d1b35,#0a1628,#0d2040)",borderBottom:"1px solid #1e3a5f",padding:"0 24px"},
  inner:{maxWidth:1400,margin:"0 auto"},
  tabs:{display:"flex",gap:4,marginTop:12},
  body:{maxWidth:1400,margin:"0 auto",padding:"24px"},
  filterBar:{display:"flex",flexWrap:"wrap",gap:10,marginBottom:24,background:"#111827",border:"1px solid #1e293b",borderRadius:10,padding:16},
  grid6:{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(178px,1fr))",gap:14,marginBottom:28},
  card:{background:"#111827",border:"1px solid #1e293b",borderRadius:12,padding:18},
  sectionTitle:{fontSize:12,fontWeight:700,color:"#64748b",letterSpacing:0.6,textTransform:"uppercase",marginBottom:14},
  table:{width:"100%",borderCollapse:"collapse",fontSize:13},
  th:{padding:"10px 12px",textAlign:"left",color:"#475569",fontWeight:600,fontSize:11,textTransform:"uppercase",letterSpacing:0.4,whiteSpace:"nowrap"},
  td:{padding:"8px 12px",borderBottom:"1px solid #0f172a"},
};

export default function App() {
  const [tab, setTab] = useState("geral");
  const [search, setSearch] = useState("");
  const [fUF, setFUF] = useState("Todos");
  const [fReg, setFReg] = useState("Todas");
  const [fPorte, setFPorte] = useState("Todos");
  const [fServ, setFServ] = useState("Todos");
  const [selMun, setSelMun] = useState(null);
  const [selEst, setSelEst] = useState(null);
  const [page, setPage] = useState(1);
  const PP = 25;

  const ufs = useMemo(() => ["Todos",...new Set(MUN.map(d=>d.uf))].sort(),[]);

  const filtered = useMemo(() => {
    let d = MUN;
    if (fUF!=="Todos") d=d.filter(m=>m.uf===fUF);
    if (fReg!=="Todas") d=d.filter(m=>m.regiao===fReg);
    if (fPorte!=="Todos") d=d.filter(m=>m.porte===fPorte);
    if (fServ!=="Todos") {
      const k={PAIF:"paif",SCFV:"scfv",EV:"ev",LAS:"las",Acessuas:"acessuas","Primeira Infância":"pi"}[fServ];
      if(k) d=d.filter(m=>m[k]===1);
    }
    if (search.trim().length>1) {
      const q=search.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"");
      d=d.filter(m=>m.municipio.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g,"").includes(q));
    }
    return d;
  }, [fUF,fReg,fPorte,fServ,search]);

  const totais = useMemo(()=>({
    mun:filtered.length,
    cras:filtered.reduce((s,d)=>s+(d.cras||0),0),
    vl_pac:filtered.reduce((s,d)=>s+(d.vl_pac||0),0),
    vl_exec:filtered.reduce((s,d)=>s+(d.vl_exec||0),0),
    familias:filtered.reduce((s,d)=>s+(d.familias||0),0),
    saldo_psb:filtered.reduce((s,d)=>s+(d.saldo_psb||0),0),
  }),[filtered]);

  const pageData = useMemo(()=>filtered.slice((page-1)*PP,page*PP),[filtered,page]);
  const totalPages = Math.ceil(filtered.length/PP);
  useEffect(()=>setPage(1),[fUF,fReg,fPorte,fServ,search]);

  const porRegiao = useMemo(()=>{
    const a={};
    filtered.forEach(d=>{
      if(!a[d.regiao]) a[d.regiao]={regiao:d.regiao,cras:0,mun:0,vl:0};
      a[d.regiao].cras+=d.cras||0; a[d.regiao].mun+=1; a[d.regiao].vl+=d.vl_pac||0;
    });
    return Object.values(a).sort((a,b)=>b.cras-a.cras);
  },[filtered]);

  const porPorte = useMemo(()=>{
    const a={};
    filtered.forEach(d=>{
      if(!d.porte) return;
      if(!a[d.porte]) a[d.porte]={porte:d.porte,count:0};
      a[d.porte].count+=1;
    });
    return ["Pequeno I","Pequeno II","Médio","Grande","Metrópole"].filter(p=>a[p]).map(p=>a[p]);
  },[filtered]);

  const servCov = useMemo(()=>{
    const tot = filtered.length||1;
    return [["PAIF","paif"],["SCFV","scfv"],["EV","ev"],["LAS","las"],["Acessuas","acessuas"],["PI","pi"]].map(([n,k])=>{
      const sim=filtered.filter(d=>d[k]===1).length;
      return {name:n,sim,pct:Math.round(sim/tot*100)};
    });
  },[filtered]);

  const topSaldo = useMemo(()=>[...filtered].filter(d=>d.saldo_psb>0).sort((a,b)=>b.saldo_psb-a.saldo_psb).slice(0,10),[filtered]);

  const tabBtn = (id,label) => (
    <button key={id} onClick={()=>setTab(id)} style={{
      padding:"8px 18px",border:"none",cursor:"pointer",fontSize:13,fontWeight:600,borderRadius:"6px 6px 0 0",
      background:tab===id?"#0f172a":"transparent",
      color:tab===id?"#00d4aa":"#64748b",
      borderBottom:tab===id?"2px solid #00d4aa":"2px solid transparent",
    }}>{label}</button>
  );

  return (
    <div style={S.app}>
      {/* HEADER */}
      <div style={S.header}>
        <div style={S.inner}>
          <div style={{display:"flex",alignItems:"center",gap:14,padding:"16px 0 0"}}>
            <div style={{background:"linear-gradient(135deg,#00d4aa,#0066ff)",borderRadius:10,width:42,height:42,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,fontWeight:900,color:"#fff",flexShrink:0}}>▲</div>
            <div>
              <div style={{fontSize:18,fontWeight:800,color:"#fff",letterSpacing:-0.5}}>Rede PSB</div>
              <div style={{fontSize:12,color:"#475569"}}>Proteção Social Básica · Abril 2025</div>
            </div>
            <div style={{marginLeft:"auto",fontSize:12,color:"#475569",background:"#111827",padding:"4px 12px",borderRadius:6,border:"1px solid #1e3a5f"}}>
              {fmtN(MUN.length)} municípios · 26 estados
            </div>
          </div>
          <div style={S.tabs}>
            {tabBtn("geral","Visão Geral")}
            {tabBtn("municipios","Municípios")}
            {tabBtn("estados","Estados")}
            {tabBtn("graficos","Gráficos")}
          </div>
        </div>
      </div>

      <div style={S.body}>
        {/* FILTROS */}
        <div style={S.filterBar}>
          <input placeholder="🔍  Buscar município..." value={search} onChange={e=>setSearch(e.target.value)}
            style={{flex:"1 1 180px",padding:"8px 12px",background:"#0a0f1a",border:"1px solid #1e3a5f",borderRadius:7,color:"#e2e8f0",fontSize:13,outline:"none"}}/>
          <Sel val={fReg} opts={REGIOES} onChange={setFReg}/>
          <Sel val={fUF} opts={ufs} onChange={setFUF}/>
          <Sel val={fPorte} opts={PORTES} onChange={setFPorte}/>
          <Sel val={fServ} opts={["Todos",...SERVICOS]} onChange={setFServ}/>
          {(fReg!=="Todas"||fUF!=="Todos"||fPorte!=="Todos"||fServ!=="Todos"||search)&&(
            <button onClick={()=>{setFReg("Todas");setFUF("Todos");setFPorte("Todos");setFServ("Todos");setSearch("");}}
              style={{padding:"8px 14px",background:"#1e3a5f",border:"none",borderRadius:7,color:"#94a3b8",fontSize:12,cursor:"pointer"}}>
              Limpar
            </button>
          )}
          <div style={{marginLeft:"auto",fontSize:12,color:"#475569",alignSelf:"center"}}>{fmtN(filtered.length)} resultados</div>
        </div>

        {/* VISÃO GERAL */}
        {tab==="geral" && (
          <div>
            <div style={S.grid6}>
              {[
                {label:"Municípios",v:fmtN(totais.mun),icon:"🏙️",c:"#00d4aa"},
                {label:"CRAS Cofinanciados",v:fmtN(totais.cras),icon:"🏠",c:"#6366f1"},
                {label:"Vl. Pactuado/mês",v:fmtK(totais.vl_pac),icon:"📋",c:"#f59e0b"},
                {label:"Vl. Executado/mês",v:fmtK(totais.vl_exec),icon:"✅",c:"#22c55e"},
                {label:"Famílias Referenc.",v:fmtN(Math.round(totais.familias)),icon:"👨‍👩‍👧",c:"#ec4899"},
                {label:"Saldo Bloco PSB",v:fmtK(totais.saldo_psb),icon:"💰",c:"#f97316"},
              ].map(x=>(
                <div key={x.label} style={{...S.card,border:`1px solid ${x.c}22`}}>
                  <div style={{fontSize:22,marginBottom:6}}>{x.icon}</div>
                  <div style={{fontSize:22,fontWeight:800,color:x.c,letterSpacing:-0.5}}>{x.v}</div>
                  <div style={{fontSize:12,color:"#475569",marginTop:2}}>{x.label}</div>
                </div>
              ))}
            </div>

            <div style={{marginBottom:28}}>
              <div style={S.sectionTitle}>Cobertura de Serviços</div>
              <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(190px,1fr))",gap:12}}>
                {servCov.map((s,i)=>(
                  <div key={s.name} style={S.card}>
                    <div style={{display:"flex",justifyContent:"space-between",marginBottom:8}}>
                      <span style={{fontSize:13,fontWeight:600}}>{s.name}</span>
                      <span style={{fontSize:13,color:CKCOL[i],fontWeight:700}}>{s.pct}%</span>
                    </div>
                    <div style={{background:"#1e293b",borderRadius:4,height:6}}>
                      <div style={{width:`${s.pct}%`,background:`linear-gradient(90deg,${CKCOL[i]},${CKCOL[(i+1)%6]})`,height:6,borderRadius:4}}/>
                    </div>
                    <div style={{fontSize:11,color:"#475569",marginTop:5}}>{fmtN(s.sim)} municípios</div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20,marginBottom:28}}>
              <div style={S.card}>
                <div style={S.sectionTitle}>Por Região</div>
                {porRegiao.map(r=>(
                  <div key={r.regiao} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
                    <div style={{width:9,height:9,borderRadius:2,background:REGCOL[r.regiao]||"#64748b",flexShrink:0}}/>
                    <span style={{fontSize:13,width:100,flexShrink:0}}>{r.regiao}</span>
                    <div style={{flex:1,background:"#1e293b",borderRadius:4,height:20,position:"relative"}}>
                      <div style={{width:`${r.mun/(filtered.length||1)*100}%`,background:REGCOL[r.regiao]||"#64748b",height:"100%",borderRadius:4,opacity:0.8}}/>
                      <span style={{position:"absolute",right:8,top:2,fontSize:11,color:"#94a3b8"}}>{r.mun} mun · {r.cras} CRAS</span>
                    </div>
                  </div>
                ))}
              </div>
              <div style={S.card}>
                <div style={S.sectionTitle}>Por Porte</div>
                {porPorte.map((p,i)=>(
                  <div key={p.porte} style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}>
                    <div style={{width:9,height:9,borderRadius:2,background:CKCOL[i],flexShrink:0}}/>
                    <span style={{fontSize:13,width:90,flexShrink:0}}>{p.porte}</span>
                    <div style={{flex:1,background:"#1e293b",borderRadius:4,height:20,position:"relative"}}>
                      <div style={{width:`${p.count/(filtered.length||1)*100}%`,background:CKCOL[i],height:"100%",borderRadius:4,opacity:0.8}}/>
                      <span style={{position:"absolute",right:8,top:2,fontSize:11,color:"#94a3b8"}}>{fmtN(p.count)}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div style={S.card}>
              <div style={S.sectionTitle}>Top 10 · Maior Saldo Bloco PSB</div>
              <div style={{overflowX:"auto"}}>
                <table style={S.table}>
                  <thead><tr style={{borderBottom:"1px solid #1e293b"}}>
                    {["#","Município","UF","Porte","CRAS","Vl.Pac/mês","Saldo PSB"].map(h=><th key={h} style={S.th}>{h}</th>)}
                  </tr></thead>
                  <tbody>{topSaldo.map((m,i)=>(
                    <tr key={m.ibge} style={{cursor:"pointer"}} onClick={()=>{setSelMun(m);setTab("municipios");}}
                      onMouseEnter={e=>e.currentTarget.style.background="#0f172a"}
                      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      <td style={{...S.td,color:"#475569"}}>{i+1}</td>
                      <td style={{...S.td,color:"#e2e8f0",fontWeight:600}}>{m.municipio}</td>
                      <td style={S.td}><span style={{background:"#1e3a5f",padding:"2px 7px",borderRadius:4,color:"#93c5fd",fontSize:11}}>{m.uf}</span></td>
                      <td style={{...S.td,color:"#64748b"}}>{m.porte}</td>
                      <td style={{...S.td,color:"#a855f7",textAlign:"center"}}>{m.cras}</td>
                      <td style={{...S.td,color:"#f59e0b"}}>{fmtBRL(m.vl_pac)}</td>
                      <td style={{...S.td,color:"#00d4aa",fontWeight:700}}>{fmtBRL(m.saldo_psb)}</td>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* MUNICÍPIOS */}
        {tab==="municipios" && (
          selMun ? (
            <MunDetail m={selMun} onBack={()=>setSelMun(null)}/>
          ) : (
            <>
              <div style={{overflowX:"auto",...S.card,padding:0,marginBottom:16}}>
                <table style={S.table}>
                  <thead><tr style={{background:"#0f172a"}}>
                    {["IBGE","Município","UF","Região","Porte","CRAS","PAIF","SCFV","EV","LAS","Acess","PI","Pac/mês","Saldo PSB",""].map(h=><th key={h} style={S.th}>{h}</th>)}
                  </tr></thead>
                  <tbody>{pageData.map(m=>(
                    <tr key={m.ibge} style={{cursor:"pointer"}} onClick={()=>setSelMun(m)}
                      onMouseEnter={e=>e.currentTarget.style.background="#0f172a"}
                      onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                      <td style={{...S.td,color:"#475569",fontSize:11}}>{m.ibge}</td>
                      <td style={{...S.td,color:"#e2e8f0",fontWeight:600,whiteSpace:"nowrap"}}>{m.municipio}</td>
                      <td style={S.td}><span style={{background:"#1e3a5f",padding:"2px 7px",borderRadius:4,color:"#93c5fd",fontSize:11}}>{m.uf}</span></td>
                      <td style={{...S.td,color:"#64748b",whiteSpace:"nowrap"}}>{m.regiao}</td>
                      <td style={{...S.td,color:"#94a3b8",whiteSpace:"nowrap"}}>{m.porte}</td>
                      <td style={{...S.td,color:"#a855f7",textAlign:"center"}}>{m.cras}</td>
                      {["paif","scfv","ev","las","acessuas","pi"].map(k=>(
                        <td key={k} style={{...S.td,textAlign:"center"}}>
                          <span style={{color:m[k]===1?"#00d4aa":"#374151",fontSize:14}}>{m[k]===1?"✓":"·"}</span>
                        </td>
                      ))}
                      <td style={{...S.td,color:"#f59e0b",whiteSpace:"nowrap"}}>{fmtBRL(m.vl_pac)}</td>
                      <td style={{...S.td,color:"#00d4aa",fontWeight:600,whiteSpace:"nowrap"}}>{fmtBRL(m.saldo_psb)}</td>
                      <td style={{...S.td,color:"#475569"}}>›</td>
                    </tr>
                  ))}</tbody>
                </table>
              </div>
              <div style={{display:"flex",justifyContent:"center",gap:8,alignItems:"center"}}>
                {[["«",1],["‹",page-1]].map(([l,p])=>(
                  <button key={l} disabled={page<=1} onClick={()=>setPage(p)}
                    style={{padding:"6px 12px",background:page<=1?"#0a0f1a":"#111827",border:"1px solid #1e293b",borderRadius:6,color:page<=1?"#374151":"#94a3b8",cursor:page<=1?"default":"pointer",fontSize:14}}>{l}</button>
                ))}
                <span style={{fontSize:13,color:"#64748b"}}>Pág {page} / {totalPages}</span>
                {[["›",page+1],["»",totalPages]].map(([l,p])=>(
                  <button key={l} disabled={page>=totalPages} onClick={()=>setPage(p)}
                    style={{padding:"6px 12px",background:page>=totalPages?"#0a0f1a":"#111827",border:"1px solid #1e293b",borderRadius:6,color:page>=totalPages?"#374151":"#94a3b8",cursor:page>=totalPages?"default":"pointer",fontSize:14}}>{l}</button>
                ))}
              </div>
            </>
          )
        )}

        {/* ESTADOS */}
        {tab==="estados" && (
          selEst ? (
            <EstDetail e={selEst} mun={filtered} onBack={()=>setSelEst(null)}/>
          ) : (
            <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(310px,1fr))",gap:14}}>
              {ESTADOS.map(e=>(
                <div key={e.uf} onClick={()=>setSelEst(e)}
                  style={{...S.card,cursor:"pointer",transition:"all 0.15s"}}
                  onMouseEnter={el=>{el.currentTarget.style.border="1px solid #1e3a5f";el.currentTarget.style.transform="translateY(-2px)";}}
                  onMouseLeave={el=>{el.currentTarget.style.border="1px solid #1e293b";el.currentTarget.style.transform="translateY(0)";}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:12}}>
                    <div>
                      <div style={{fontSize:24,fontWeight:800,color:"#e2e8f0"}}>{e.uf}</div>
                      <div style={{fontSize:13,color:"#64748b"}}>{e.estado}</div>
                    </div>
                    <div style={{textAlign:"right"}}>
                      <span style={{background:`${REGCOL[e.regiao]}22`,color:REGCOL[e.regiao],padding:"3px 10px",borderRadius:6,fontSize:11,fontWeight:600}}>{e.regiao}</span>
                      <div style={{fontSize:12,color:"#475569",marginTop:4}}>{fmtN(e.total_mun)} municípios</div>
                    </div>
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:12}}>
                    {[["CRAS",fmtN(e.cras)],["PAIF",fmtN(e.paif)],["SCFV",fmtN(e.scfv)]].map(([l,v])=>(
                      <div key={l} style={{background:"#0a0f1a",borderRadius:7,padding:"8px 10px"}}>
                        <div style={{fontSize:15,fontWeight:700,color:"#e2e8f0"}}>{v}</div>
                        <div style={{fontSize:10,color:"#475569"}}>{l}</div>
                      </div>
                    ))}
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between",borderTop:"1px solid #1e293b",paddingTop:10}}>
                    <div><div style={{fontSize:11,color:"#475569"}}>Pactuado/mês</div><div style={{fontSize:13,color:"#f59e0b",fontWeight:700}}>{fmtK(e.vl_pac)}</div></div>
                    <div style={{textAlign:"right"}}><div style={{fontSize:11,color:"#475569"}}>Saldo PSB</div><div style={{fontSize:13,color:"#00d4aa",fontWeight:700}}>{fmtK(e.saldo_psb)}</div></div>
                  </div>
                </div>
              ))}
            </div>
          )
        )}

        {/* GRÁFICOS */}
        {tab==="graficos" && (
          <div style={{display:"flex",flexDirection:"column",gap:24}}>
            <div style={S.card}>
              <div style={S.sectionTitle}>CRAS por Região</div>
              <ResponsiveContainer width="100%" height={260}>
                <BarChart data={porRegiao} margin={{top:4,right:20,left:0,bottom:4}}>
                  <XAxis dataKey="regiao" tick={{fill:"#64748b",fontSize:12}} axisLine={false} tickLine={false}/>
                  <YAxis tick={{fill:"#64748b",fontSize:11}} axisLine={false} tickLine={false}/>
                  <Tooltip contentStyle={{background:"#0f172a",border:"1px solid #1e3a5f",borderRadius:8}} labelStyle={{color:"#e2e8f0"}} itemStyle={{color:"#00d4aa"}}/>
                  <Bar dataKey="cras" name="CRAS" radius={[4,4,0,0]}>
                    {porRegiao.map(r=><Cell key={r.regiao} fill={REGCOL[r.regiao]||"#64748b"}/>)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div style={S.card}>
              <div style={S.sectionTitle}>Valor Pactuado Mensal por Estado (Top 15)</div>
              <ResponsiveContainer width="100%" height={320}>
                <BarChart data={[...ESTADOS].sort((a,b)=>b.vl_pac-a.vl_pac).slice(0,15)} layout="vertical" margin={{top:4,right:70,left:30,bottom:4}}>
                  <XAxis type="number" tick={{fill:"#64748b",fontSize:10}} axisLine={false} tickLine={false} tickFormatter={v=>`R$${(v/1e6).toFixed(1)}M`}/>
                  <YAxis dataKey="uf" type="category" tick={{fill:"#94a3b8",fontSize:12}} axisLine={false} tickLine={false} width={28}/>
                  <Tooltip contentStyle={{background:"#0f172a",border:"1px solid #1e3a5f",borderRadius:8}} formatter={v=>[fmtBRL(v),"Pactuado/mês"]}/>
                  <Bar dataKey="vl_pac" name="Valor Pactuado" fill="#6366f1" radius={[0,4,4,0]}/>
                </BarChart>
              </ResponsiveContainer>
            </div>

            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
              <div style={S.card}>
                <div style={S.sectionTitle}>Municípios por Porte</div>
                <ResponsiveContainer width="100%" height={250}>
                  <PieChart>
                    <Pie data={porPorte} dataKey="count" nameKey="porte" cx="50%" cy="50%" outerRadius={90}>
                      {porPorte.map((p,i)=><Cell key={p.porte} fill={CKCOL[i]}/>)}
                    </Pie>
                    <Tooltip contentStyle={{background:"#0f172a",border:"1px solid #1e3a5f",borderRadius:8}} formatter={v=>[fmtN(v),"Municípios"]}/>
                    <Legend wrapperStyle={{fontSize:12,color:"#64748b"}}/>
                  </PieChart>
                </ResponsiveContainer>
              </div>
              <div style={S.card}>
                <div style={S.sectionTitle}>Cobertura de Serviços (%)</div>
                <ResponsiveContainer width="100%" height={250}>
                  <BarChart data={servCov} margin={{top:4,right:10,left:0,bottom:4}}>
                    <XAxis dataKey="name" tick={{fill:"#64748b",fontSize:11}} axisLine={false} tickLine={false}/>
                    <YAxis domain={[0,100]} tick={{fill:"#64748b",fontSize:11}} axisLine={false} tickLine={false} unit="%"/>
                    <Tooltip contentStyle={{background:"#0f172a",border:"1px solid #1e3a5f",borderRadius:8}} formatter={v=>[`${v}%`,"Cobertura"]}/>
                    <Bar dataKey="pct" radius={[4,4,0,0]}>
                      {servCov.map((s,i)=><Cell key={s.name} fill={CKCOL[i]}/>)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

function Sel({val,opts,onChange}) {
  return <select value={val} onChange={e=>onChange(e.target.value)} style={{padding:"8px 12px",background:"#0a0f1a",border:"1px solid #1e3a5f",borderRadius:7,color:val===opts[0]?"#64748b":"#e2e8f0",fontSize:13,cursor:"pointer",outline:"none",minWidth:100}}>
    {opts.map(o=><option key={o} value={o}>{o}</option>)}
  </select>;
}

function MunDetail({m,onBack}) {
  const fmtBRL2 = v => v==null?"—":new Intl.NumberFormat("pt-BR",{style:"currency",currency:"BRL",maximumFractionDigits:2}).format(v);
  const fmtN = v => v==null?"—":new Intl.NumberFormat("pt-BR").format(v);
  const REGCOL2 = {Norte:"#22c55e",Nordeste:"#f59e0b",Sudeste:"#3b82f6",Sul:"#a855f7","Centro-Oeste":"#ef4444"};
  const CKCOL2 = ["#00d4aa","#f59e0b","#6366f1","#ec4899","#22c55e","#f97316"];
  const S2 = {card:{background:"#111827",border:"1px solid #1e293b",borderRadius:12,padding:24},sT:{fontSize:12,fontWeight:700,color:"#64748b",letterSpacing:0.6,textTransform:"uppercase",marginBottom:14}};
  return (
    <div>
      <button onClick={onBack} style={{background:"none",border:"none",color:"#00d4aa",cursor:"pointer",fontSize:13,marginBottom:18,padding:0}}>‹ Voltar</button>
      <div style={S2.card}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:24}}>
          <div>
            <div style={{fontSize:26,fontWeight:800,color:"#e2e8f0",marginBottom:6}}>{m.municipio}</div>
            <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
              <span style={{background:"#1e3a5f",padding:"3px 10px",borderRadius:5,color:"#93c5fd",fontSize:13}}>{m.uf}</span>
              <span style={{background:"#1e293b",padding:"3px 10px",borderRadius:5,color:"#64748b",fontSize:13}}>{m.regiao}</span>
              <span style={{background:"#1e293b",padding:"3px 10px",borderRadius:5,color:"#64748b",fontSize:13}}>{m.porte}</span>
              <span style={{background:"#1e293b",padding:"3px 10px",borderRadius:5,color:"#64748b",fontSize:13}}>{m.canal}</span>
            </div>
          </div>
          <div style={{textAlign:"right",background:"#0a0f1a",borderRadius:8,padding:"10px 16px"}}>
            <div style={{fontSize:12,color:"#475569"}}>IBGE</div>
            <div style={{fontSize:18,fontWeight:700,color:"#475569"}}>{m.ibge}</div>
          </div>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(160px,1fr))",gap:14,marginBottom:24}}>
          {[["CRAS Cofinanciados",m.cras,"#a855f7"],["Centros de Convivência",m.cc,"#6366f1"],["CRAS Ativos",m.cras_cofin,"#3b82f6"],["Famílias Referenciadas",fmtN(m.familias),"#ec4899"]].map(([l,v,c])=>(
            <div key={l} style={{background:"#0a0f1a",borderRadius:8,padding:14}}>
              <div style={{fontSize:20,fontWeight:800,color:c}}>{v??0}</div>
              <div style={{fontSize:11,color:"#475569",marginTop:2}}>{l}</div>
            </div>
          ))}
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
          <div>
            <div style={S2.sT}>Serviços</div>
            {[["PAIF","paif"],["SCFV","scfv"],["Equipes Volantes","ev"],["Lanchas Sociais","las"],["Acessuas","acessuas"],["Primeira Infância","pi"]].map(([l,k])=>(
              <div key={k} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderBottom:"1px solid #0f172a"}}>
                <span style={{fontSize:13,color:"#94a3b8"}}>{l}</span>
                <span style={{background:m[k]===1?"#00d4aa22":"#1e293b",color:m[k]===1?"#00d4aa":"#475569",padding:"3px 12px",borderRadius:5,fontSize:12,fontWeight:600}}>
                  {m[k]===1?"✓ Sim":"✗ Não"}
                </span>
              </div>
            ))}
          </div>
          <div>
            <div style={S2.sT}>Financeiro</div>
            {[["Valor Pactuado/mês",m.vl_pac,"#f59e0b"],["Valor Executado/mês",m.vl_exec,"#22c55e"],["Saldo Bloco PSB",m.saldo_psb,"#00d4aa"],["Saldo Acessuas",m.saldo_ac,"#6366f1"],["Saldo Primeira Infância",m.saldo_pi,"#ec4899"]].map(([l,v,c])=>(
              <div key={l} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"7px 0",borderBottom:"1px solid #0f172a"}}>
                <span style={{fontSize:13,color:"#94a3b8"}}>{l}</span>
                <span style={{fontSize:13,fontWeight:700,color:c}}>{fmtBRL2(v)}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

function EstDetail({e,mun,onBack}) {
  const fmtBRL2 = v => v==null?"—":new Intl.NumberFormat("pt-BR",{style:"currency",currency:"BRL",maximumFractionDigits:2}).format(v);
  const fmtN = v => v==null?"—":new Intl.NumberFormat("pt-BR").format(v);
  const fmtK = v => v==null?"—":v>=1e6?`R$ ${(v/1e6).toFixed(2)}M`:fmtBRL2(v);
  const REGCOL2 = {Norte:"#22c55e",Nordeste:"#f59e0b",Sudeste:"#3b82f6",Sul:"#a855f7","Centro-Oeste":"#ef4444"};
  const munEst = mun.filter(m=>m.uf===e.uf);
  const S2 = {card:{background:"#111827",border:"1px solid #1e293b",borderRadius:12,padding:24},sT:{fontSize:12,fontWeight:700,color:"#64748b",letterSpacing:0.6,textTransform:"uppercase",marginBottom:14}};
  return (
    <div>
      <button onClick={onBack} style={{background:"none",border:"none",color:"#00d4aa",cursor:"pointer",fontSize:13,marginBottom:18,padding:0}}>‹ Voltar</button>
      <div style={S2.card}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:24}}>
          <div>
            <div style={{fontSize:28,fontWeight:800,color:"#e2e8f0"}}>{e.estado}</div>
            <div style={{display:"flex",gap:8,marginTop:6}}>
              <span style={{background:"#1e3a5f",padding:"3px 10px",borderRadius:5,color:"#93c5fd",fontSize:14,fontWeight:700}}>{e.uf}</span>
              <span style={{background:`${REGCOL2[e.regiao]}22`,color:REGCOL2[e.regiao],padding:"3px 10px",borderRadius:5,fontSize:13}}>{e.regiao}</span>
            </div>
          </div>
          <div style={{textAlign:"right",background:"#0a0f1a",borderRadius:8,padding:"12px 18px"}}>
            <div style={{fontSize:26,fontWeight:800,color:"#00d4aa"}}>{fmtN(e.total_mun)}</div>
            <div style={{fontSize:11,color:"#475569"}}>municípios</div>
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(200px,1fr))",gap:14,marginBottom:24}}>
          {[["CRAS",fmtN(e.cras),"#a855f7"],["Pactuado/mês",fmtK(e.vl_pac),"#f59e0b"],["Executado/mês",fmtK(e.vl_exec),"#22c55e"],["Saldo PSB",fmtK(e.saldo_psb),"#00d4aa"]].map(([l,v,c])=>(
            <div key={l} style={{background:"#0a0f1a",borderRadius:8,padding:16}}>
              <div style={{fontSize:20,fontWeight:800,color:c}}>{v}</div>
              <div style={{fontSize:12,color:"#475569",marginTop:2}}>{l}</div>
            </div>
          ))}
        </div>
        <div style={S2.sT}>Municípios com Serviço Ativo</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(120px,1fr))",gap:10,marginBottom:24}}>
          {[["PAIF","paif"],["SCFV","scfv"],["EV","ev"],["LAS","las"],["Acessuas","acessuas"],["PI","pi"]].map(([l,k])=>(
            <div key={k} style={{background:"#0a0f1a",borderRadius:8,padding:12,textAlign:"center"}}>
              <div style={{fontSize:20,fontWeight:800,color:"#6366f1"}}>{fmtN(e[k])}</div>
              <div style={{fontSize:11,color:"#475569"}}>{l}</div>
              <div style={{fontSize:10,color:"#374151"}}>{Math.round(e[k]/(e.total_mun||1)*100)}%</div>
            </div>
          ))}
        </div>
        {munEst.length>0&&(
          <>
            <div style={S2.sT}>Municípios ({fmtN(munEst.length)})</div>
            <div style={{overflowX:"auto",maxHeight:360,overflowY:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead style={{position:"sticky",top:0,background:"#0f172a"}}>
                  <tr>{["Município","Porte","CRAS","PAIF","SCFV","Pac/mês","Saldo PSB"].map(h=>(
                    <th key={h} style={{padding:"8px 10px",textAlign:"left",color:"#475569",fontWeight:600,fontSize:10,textTransform:"uppercase"}}>{h}</th>
                  ))}</tr>
                </thead>
                <tbody>{munEst.slice(0,200).map(m=>(
                  <tr key={m.ibge} style={{borderBottom:"1px solid #0f172a"}}>
                    <td style={{padding:"6px 10px",color:"#e2e8f0"}}>{m.municipio}</td>
                    <td style={{padding:"6px 10px",color:"#64748b"}}>{m.porte}</td>
                    <td style={{padding:"6px 10px",color:"#a855f7",textAlign:"center"}}>{m.cras}</td>
                    <td style={{padding:"6px 10px",textAlign:"center",color:m.paif===1?"#00d4aa":"#374151"}}>{m.paif===1?"✓":"·"}</td>
                    <td style={{padding:"6px 10px",textAlign:"center",color:m.scfv===1?"#00d4aa":"#374151"}}>{m.scfv===1?"✓":"·"}</td>
                    <td style={{padding:"6px 10px",color:"#f59e0b",whiteSpace:"nowrap"}}>{fmtBRL2(m.vl_pac)}</td>
                    <td style={{padding:"6px 10px",color:"#00d4aa",whiteSpace:"nowrap"}}>{fmtBRL2(m.saldo_psb)}</td>
                  </tr>
                ))}</tbody>
              </table>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
